+  private getKeysetPagination(opts: CrudOptions) {
+    if (!opts.cursor && !(opts.orderBy && opts.limit)) {
+      return null;
+    }
+    if (opts.cursor && !opts.orderBy) {
+      throw new BadRequestException('cursor requires orderBy');
+    }
+    if (opts.cursor && opts.offset !== undefined) {
+      throw new BadRequestException('cursor cannot be used with offset');
+    }
+    // A cursor only has paging meaning when a page size is present. Preserve the
+    // existing non-paginated orderBy behavior otherwise.
+    if (!opts.limit) {
+      return null;
+    }
+
+    const order = this.getCursorOrder(opts.orderBy);
+    const cursor = opts.cursor
+      ? this.parseCursor(opts.cursor, order)
+      : undefined;
+    return {
+      limit: opts.limit,
+      order,
+      orderBy: order.map(({ field, direction }) => ({ [field]: direction })),
+      cursor,
+      query: cursor ? this.getCursorQuery(cursor, order) : undefined,
+    };
+  }
+
+  private getCursorOrder(orderBy: any): { field: string; direction: 'asc' | 'desc' }[] {
+    if (!orderBy || (typeof orderBy !== 'object' && !Array.isArray(orderBy))) {
+      throw new BadRequestException('cursor pagination requires a valid orderBy');
+    }
+    const order: { field: string; direction: 'asc' | 'desc' }[] = [];
+    for (const part of Array.isArray(orderBy) ? orderBy : [orderBy]) {
+      if (!part || typeof part !== 'object' || Array.isArray(part)) {
+        throw new BadRequestException('cursor pagination requires a valid orderBy');
+      }
+      for (const [field, value] of Object.entries(part)) {
+        const direction = this.normalizeCursorDirection(value);
+        if (!direction) {
+          throw new BadRequestException('cursor pagination only supports asc and desc orderBy directions');
+        }
+        order.push({ field, direction });
+      }
+    }
+    if (!order.length) {
+      throw new BadRequestException('cursor pagination requires a valid orderBy');
+    }
+    if (!order.some(({ field }) => field === this.crudConfig.id_field)) {
+      order.push({ field: this.crudConfig.id_field, direction: 'asc' });
+    }
+    return order;
+  }
+
+  private normalizeCursorDirection(value: any): 'asc' | 'desc' | undefined {
+    if (value === 1) return 'asc';
+    if (value === -1) return 'desc';
+    const direction = typeof value === 'string' ? value.toLowerCase() : '';
+    return direction === 'asc' || direction === 'desc' ? direction : undefined;
+  }
+
+  private parseCursor(cursor: string, order: { field: string; direction: 'asc' | 'desc' }[]) {
+    let parsed: Record<string, any>;
+    try {
+      if (!/^[A-Za-z0-9+/]*={0,2}$/.test(cursor) || cursor.length % 4 !== 0) {
+        throw new Error('invalid base64');
+      }
+      parsed = JSON.parse(Buffer.from(cursor, 'base64').toString('utf8'));
+    } catch (_) {
+      throw new BadRequestException('cursor must be Base64-encoded JSON');
+    }
+    if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) {
+      throw new BadRequestException('cursor must be Base64-encoded JSON');
+    }
+    const encodedOrder = order.map(({ field, direction }) => `${field}:${direction}`).join(',');
+    if (parsed.__sort !== encodedOrder) {
+      throw new BadRequestException('cursor sort does not match orderBy');
+    }
+    for (const { field } of order) {
+      if (!(field in parsed)) {
+        throw new BadRequestException(`cursor is missing ${field}`);
+      }
+    }
+    if (!(this.crudConfig.id_field in parsed)) {
+      throw new BadRequestException(`cursor is missing ${this.crudConfig.id_field}`);
+    }
+    return parsed;
+  }
